"""Tests for label definition functions.
Pure unit tests (Layer 3) - no dependencies on fakes or external systems. """
from erk_shared.gateway.github.objective_issues import ( get_erk_label_definitions, get_required_erk_labels, )
def test_get_erk_label_definitions_returns_five_labels() -> None: """Test that get_erk_label_definitions returns all four expected labels.""" labels = get_erk_label_definitions()
assert len(labels) == 4
def test_get_erk_label_definitions_excludes_erk_pr_from_definitions() -> None: """Test that erk-pr label is NOT included (plans identified by title prefix).""" labels = get_erk_label_definitions()
label_names = [label.name for label in labels] assert "erk-pr" not in label_names assert "erk-core" not in label_names
def test_get_erk_label_definitions_contains_erk_learn() -> None: """Test that erk-learn label is included with correct properties.""" labels = get_erk_label_definitions()
